  ('social-worker-moex-02328', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者不是後現代社會工作的觀點？', '["強調實務知識是由社會工作者和案主互動過程中創造出來的", "強調情境參與者的直觀，透過社會論述可建構知識", "強調所有參與者是平權的，因此社會工作者應抱持謙虛的態度", "強調社會工作評量是一個了解問題和情境的過程，因此陪伴案主尋找自己內在的問題，使治療更有效能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
