  ('social-worker-moex-02330', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者才是社會工作者應持有的認知？', '["人的自我決定通常是深思熟慮的結果，應予以尊重", "在助人過程中自我決定是絕對的最高價值原則", "案主無法具有建設性決定的能力時，必要時社會工作者得以專業權威來介入", "在自我決定的情況下，社會工作者不必為案主自我決定權的適當與否而奮戰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
